head.script:
//

scwin.firstCheck=0;
scwin.firstCheck1=0;
scwin.dateStr ="";
scwin.workEndDt = "";

scwin.iCheck = ""; //수입구분
scwin.oCheck = ""; //수출구분
scwin.toDay;
scwin.DDate;


scwin.onpageload = function() {
    gen_tr_1.insertChild(0);
    scwin.toDay = WebSquare.date.getCurrentServerDate().substring(0, 8);
    scwin.DDate = scwin.toDay;
    acb_payCmisKnd.setSelectedIndex(0);
    ed_cvsslMgntNo.focus();
    scwin.dateStr = scwin.toDay;

    const codeOptions1 = [
        { grpCd : "OP202", compID : "acb_payCmisKnd"} //<%= GauceUtil.getCodeList("SD113", new int[] {1,3}, new String[] {DsConstants.ODR_CNTR, "1" }) %>">
    ];

    $c.data.setCommonCode(codeOptions1, scwin.callback1);
};

//-------------------------------------------------------------------------
// 조회
//------------------------------------------------------------------------- 
scwin.f_Retrieve = async function() {

    var rtn = await $c.gus.cfValidate([ed_cvsslMgntNo,acb_payCmisKnd]);
	// 필수항목 체크 
	if(!rtn){
		return false;
	};

	dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    dma_condition.set("payCmisKnd", acb_payCmisKnd.getValue());
    dma_condition.set("payCmisKndRpc", ed_payCmisKndRpc.getValue());

    $c.sbm.execute(sbm_retrieve);
};

scwin.callback1 = function(){

    let ds_comCode = $p.getComponentById(acb_payCmisKnd.getDataListInfo().id);
    for(var i=0;i<ds_comCode.getColCnt();i++) {
        if(ds_comCode.getColumnInfo(i).id == "cd") {
            ds_comCode.getCellInfo(i).options["dataType"] = "number";
        }
    }
    ds_comCode.sort("cd",0);
}


scwin.sbm_retrieve_submitDone = async function(){

    var impCls = "";
    var expCls = "";
    var cvsslCompleteYn = "";
    var sumPrice ="";
    ed_vsslNm.setValue(ds_carryingVesselBasisInfo.getCellData(0, "vsslNm"));
    ed_lineNm.setValue(ds_carryingVesselBasisInfo.getCellData(0, "lineNm"));
    ed_shpCoNm.setValue(ds_carryingVesselBasisInfo.getCellData(0, "shpCoNm"));	
    ed_impPortcnt.setValue(ds_carryingVesselBasisInfo.getCellData(0, "impPortcnt")); //수입구분
    ed_expPortcnt.setValue(ds_carryingVesselBasisInfo.getCellData(0, "expPortcnt")); //수출여부
    ed_impRepKcg.setValue(ds_carryingVesselBasisInfo.getCellData(0, "impRepKcg"));	
    ed_expRepKcg.setValue(ds_carryingVesselBasisInfo.getCellData(0, "expRepKcg"));	
    //expClsCd = acb_expClsCd.ValueOfIndex("name", acb_expClsCd.Index); 
    ed_wrkPlNm.setValue(ds_carryingVesselBasisInfo.getCellData(0, "wrkPlNm"));
    ed_arrvlportDtm.setValue($c.gus.cfGetFormatStr(ds_carryingVesselBasisInfo.getCellData(0, "arrvlportDtm"), "####/##/## ##:##"));
    ed_deprtportDtm.setValue($c.gus.cfGetFormatStr(ds_carryingVesselBasisInfo.getCellData(0, "deprtportDtm"), "####/##/## ##:##"));
    ed_stvchrgcls.setValue(ds_carryingVesselBasisInfo.getCellData(0, "stvChrgCls"));	
    if(ed_stvchrgcls.getValue()=="W"){
        ed_stvchrgcls.setValue("YES");
    }else{
        ed_stvchrgcls.setValue("NO");
    }
    ed_dchrDropRgn.setValue(ds_carryingVesselBasisInfo.getCellData(0, "dchrDropRgn")); //양적하지
   //본선완료여부
    if(ds_carryingVesselBasisInfo.getCellData(0, "cvsslCompleteYn")== 0){
        cvsslCompleteYn = "N";
    } else {
        cvsslCompleteYn = "Y";
    };
    if(ed_impPortcnt.getValue() ==""){
        impCls="";
        ed_impCls.setValue("");
    }else{
        impCls="수입";
         ed_impCls.setValue(impCls);
    }

    if(ed_expPortcnt.getValue( )==""){
       expCls="";
       ed_expCls.setValue("");
    }else{
       expCls="수출";
        ed_expCls.setValue(expCls);
    };


    for(var i=0; i < ds_carryingVesselCompletionInformation.getRowCount(); i++ ){
        if(i != 0){
            gen_tr_1.insertChild(i);

        }

        if(ds_carryingVesselCompletionInformation.getCellData(i,"cvsslWrkCompleteYn") == "1"){
            $p.getComponentById(gen_tr_1.getChild(i,"ed_cvsslWrkCompleteYn").id).setValue("YES");

        } else {
            $p.getComponentById(gen_tr_1.getChild(i,"ed_cvsslWrkCompleteYn").id).setValue("NO");
        }

        $p.getComponentById(gen_tr_1.getChild(i,"ed_impExpClsNm").id).setValue(ds_carryingVesselCompletionInformation.getCellData(i,"impExpClsNm"));
       // $p.getComponentById(gen_tr_1.getChild(i,"ed_cvsslWrkCompleteYn").id).setValue(ds_carryingVesselCompletionInformation.getCellData(i,"cvsslWrkCompleteYn"));
        $p.getComponentById(gen_tr_1.getChild(i,"ed_cvsslWrkCompleteDt").id).setValue(ds_carryingVesselCompletionInformation.getCellData(i,"cvsslWrkCompleteDt"))
    }
    // ed_impExpClsNm.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsNm"));	
    // ed_cvsslWrkCompleteYn.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn"));	
    // ed_cvsslWrkCompleteDt.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));

    // if (ed_cvsslWrkCompleteYn.getValue() == "1") {
    //         ed_cvsslWrkCompleteYn.setValue("Yes");
    // } else {
    //     ed_cvsslWrkCompleteYn.setValue("No");
    // };
        gr_orderEachPaymentCommissionInfo.setFocusedCell(0, 0);

  	if(acb_payCmisKnd.getValue()=="1" || acb_payCmisKnd.getValue()=="2"){
	  	if(ds_carryingVesselBasisInfo.getCellData(ds_orderEachPaymentCommissionInfo.getRowPosition(), "stvChrgCls")=="W"){
	  		await $c.gus.cfEnableObjects([ed_clntNo,ed_clntNm,acb_adjmStdCd,btn_save,btn_Caculate,btn_DeleteShift,btn_CancelShift,btn_popUp1]);
	  		gr_orderEachPaymentCommissionInfo.setReadOnly("grid", false);
            gr_orderEachPaymentCommissionInfo.setReadOnly("column", "chk",false);

	  	}else{
	  		$c.gus.cfDisableBtn([ed_clntNo,ed_clntNm,acb_adjmStdCd,btn_save,btn_Caculate,btn_DeleteShift,btn_CancelShift,btn_popUp1]);
	  		gr_orderEachPaymentCommissionInfo.setReadOnly("grid", true);
            gr_orderEachPaymentCommissionInfo.setReadOnly("column", "chk",true)
	  	}
	}else{
		await $c.gus.cfEnableObjects([ed_clntNo,ed_clntNm,acb_adjmStdCd,btn_save,btn_Caculate,btn_DeleteShift,btn_CancelShift,btn_popUp1]);
	    gr_orderEachPaymentCommissionInfo.setReadOnly("grid", true);
        gr_orderEachPaymentCommissionInfo.setReadOnly("column","ctrlPayCmis", false);
        gr_orderEachPaymentCommissionInfo.setReadOnly("column","rmk", false);
        gr_orderEachPaymentCommissionInfo.setReadOnly("column","chk", false);
	};  


    if(ds_paymentCommissionBasisInfo.getRowCount() <=0) {
	    scwin.firstCheck =1;
	    acb_adjmStdCd.setValue(ds_paymentCommissionBasisInfo.getCellData(0,"adjmStdCd"));
		//acb_adjmStdCd.setSelectedIndex(0);
	}else{
	    scwin.firstCheck =0;
		ed_clntNo.setValue(ds_paymentCommissionBasisInfo.getCellData(0,"clntNo"));
		ed_clntNm.setValue(ds_paymentCommissionBasisInfo.getCellData(0,"clntNm"));
		acb_adjmStdCd.setValue(ds_paymentCommissionBasisInfo.getCellData(0,"adjmStdCd"));
		ed_clntNo1.setValue(ds_paymentCommissionBasisInfo.getCellData(0,"clntNo"));
	};

    if( ds_orderEachPaymentCommissionInfo.getRowCount() == 0 ) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
  	}  	

  	//alert(ds_orderEachPaymentCommissionInfo.CountRow);
    for(var i=0; i<= ds_orderEachPaymentCommissionInfo.getRowCount(); i++){
       sumPrice = sumPrice + ds_orderEachPaymentCommissionInfo.getCellData(i, "payCmis");
    	if(ds_orderEachPaymentCommissionInfo.getCellData(i,"impExpDomesticClsCd")=="I"){
    		ds_orderEachPaymentCommissionInfo.setCellData(i,"impExpDomesticClsCd", "수입");
    	}else{
    		ds_orderEachPaymentCommissionInfo.setCellData(i,"impExpDomesticClsCd", "수출");
    	}
    };
    //gr_orderEachPaymentCommissionInfo.setFooterValue("column56", sumPrice);

    ds_orderEachPaymentCommissionInfo.initRowStatus();

    totalRows.setValue(ds_orderEachPaymentCommissionInfo.getRowCount()); // 총건수 
    scwin.firstCheck1=0;

};

scwin.delF = function(e){

    gr_orderEachPaymentCommissionInfo.setFooterData("column56", 0);
    for(var i=0; i<= ds_orderEachPaymentCommissionInfo.getRowCount(); i++){
        if(ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1"){
            ds_orderEachPaymentCommissionInfo.deleteRow(i);

        }
    }
};

scwin.sbm_save_submitDone = async function(){

    await  $c.gus.cfAlertMsg(MSG_CM_INF_001);

	scwin.f_Retrieve();
}

scwin.cancelF = function(){

    $c.data.undoRow(ds_orderEachPaymentCommissionInfo, "Y");

}

scwin.btn_search_onclick = function (e) {
    scwin.f_openPopUp();
};

scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.ed_clnt_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), ed_clntNm.getValue(), 'F', 'T');
};

scwin.ed_clnt_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_clntNm, ed_clntNo, 1, false);
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.btn_Caculate_onclick = function (e) {
    scwin.f_Caculate();
};

scwin.gr_orderEachPaymentCommissionInfo_oncellclick = function (rowIndex, columnIndex, columnId) {

    var row = rowIndex;
       if(ds_orderEachPaymentCommissionInfo.getCellData(row, 'chk')=="1"){
	   if(ds_orderEachPaymentCommissionInfo.getCellData(row, 'impExpDomesticClsCd')=="수입"){
	       for (var i=0; i<= ds_carryingVesselCompletionInformation.getRowCount();  i++) {
		        if(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsCd") =="I"){
					if (ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn") == "0") { //본선미완료이면
					    $c.win.alert("수입본선은 완료가 되지 않아 지급수수료 정산을 하실수가 없습니다.");
				    	ds_orderEachPaymentCommissionInfo.setCellData(row, 'chk', "0");
				    	$c.gus.cfDisableBtn([btn_DeleteShift]);
				    	return false;
					}else{
						ds_orderEachPaymentCommissionInfo.setCellData(row, 'chk', "1");
						$c.gus.cfEnableObjects([btn_DeleteShift]);
					}
				}	
		   }
	   }else{
	       for (var i=0; i<= ds_carryingVesselCompletionInformation.getRowCount(); i++) {
		        if(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsCd") =="O"){
					if (ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn") == "0") { //본선미완료이면
					    $c.win.alert("수출본선은 완료가 되지 않아 지급수수료 정산을 하실수가 없습니다.");
						ds_orderEachPaymentCommissionInfo.setCellData(row, 'chk', "0");
						$c.gus.cfDisableBtn([btn_DeleteShift]);
						return false;
					}else{
						ds_orderEachPaymentCommissionInfo.setCellData(row, 'chk', "1"); 
						$c.gus.cfEnableObjects([btn_DeleteShift]);
					}
				}	
		   }
	   }
   }
   ds_orderEachPaymentCommissionInfo.initRowStatus();
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function(){

    var count = 0;
    var count1 =0;
    // 필수항목 체크 
	if(!$c.gus.cfValidate([ed_cvsslMgntNo,ed_clntNo,acb_adjmStdCd])){
		return;
	}

	for(var i=0; i<= ds_orderEachPaymentCommissionInfo.getRowCount() ; i++){
		if(ds_orderEachPaymentCommissionInfo.getRowStatus(i) == "D"){
	    	count1++;
	    	break;
		}
    }

	if(scwin.firstCheck1!=1){
		for(var i=0; i<= ds_orderEachPaymentCommissionInfo.getRowCount(); i++){
			if(ds_orderEachPaymentCommissionInfo.getCellData(i,"odrNo")!=""){
				if(ds_orderEachPaymentCommissionInfo.getCellData(i,"ctrlPayCmis") == ds_orderEachPaymentCommissionInfo.getOriginalCellData(i,"ctrlPayCmis")
				    && ds_orderEachPaymentCommissionInfo.getCellData(i,"payCmis") == ds_orderEachPaymentCommissionInfo.getOriginalCellData(i,"payCmis") 
				    && ds_orderEachPaymentCommissionInfo.getCellData(i,"rmk") == ds_orderEachPaymentCommissionInfo.getOriginalCellData(i,"rmk")){
					scwin.firstCheck1=0;
				}else{
					scwin.firstCheck1=1;
					break;
				}
			}
		}
	}	

    //if(!ds_orderEachPaymentCommissionInfo.IsUpdated && firstCheck1==0 ) {
    if(scwin.firstCheck1==0 && count1 <=0 ) {
    	await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["오더별 지급수수료"]);
	    return false;
	}

	for(var i=0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++){
		if(ds_orderEachPaymentCommissionInfo.getCellData(i,"chk")=="1"){
			//if(!ds_orderEachPaymentCommissionInfo.IsUpdated && ds_orderEachPaymentCommissionInfo.NameValue(i,"payCmis")==0 && ds_orderEachPaymentCommissionInfo.NameValue(i,"ctrlPayCmis")==0 ){
			if(ds_orderEachPaymentCommissionInfo.getCellData(i,"payCmis")==0 && ds_orderEachPaymentCommissionInfo.getCellData(i,"ctrlPayCmis")=="0" ){
				await $c.gus.cfAlertMsg(MSG_CM_ERR_002,["지급수수료"]);
	    		return false;
			}
		}	
	}

	/*for(var i=1; i<=ds_orderEachPaymentCommissionInfo.CountRow; i++){
		if(ds_orderEachPaymentCommissionInfo.SysStatus(i)==3 && ds_orderEachPaymentCommissionInfo.NameValue(i,"chk")==0){
			cfAlertMsg(MSG_CM_WRN_007,["수정할 데이터의 오더번호"]);
			return false;
		}
	}*/

	for(var i=0; i <= ds_orderEachPaymentCommissionInfo.getRowCount() ; i++){
		if(ds_orderEachPaymentCommissionInfo.getCellData(i,"chk")=="1" && ds_orderEachPaymentCommissionInfo.getCellData(i,"odrNo")!=""
		   && ds_orderEachPaymentCommissionInfo.getCellData(i,"payCmis")=="0" && ds_orderEachPaymentCommissionInfo.getCellData(i,"ctrlPayCmis")=="0" 
		   && ds_orderEachPaymentCommissionInfo.getCellData(i,"rmk")=="") {
			await $c.win.alert( i+"번째 데이터는 변경된 사항이 없습니다. 선택된 체크박스를 해제해 주십시오.")
			return false;
		}	
	}

	for(var i=0; i<=ds_orderEachPaymentCommissionInfo.getRowCount(); i++){
		if(ds_orderEachPaymentCommissionInfo.getCellData(i,"payCmis") <=0 && ds_orderEachPaymentCommissionInfo.getCellData(i,"ctrlPayCmis") >0 ){
			$c.win.alert("먼저 지급수수료를 계산해 주십시오.");
			return false;
		}
	}

	ds_paymentCommissionBasisInfo.setCellData(0,"clntNo", ed_clntNo.getValue());
	ds_paymentCommissionBasisInfo.setCellData(0,"adjmStdCd", acb_adjmStdCd.getValue());

	if(scwin.firstCheck !=1 && ds_paymentCommissionBasisInfo.getOriginalCellData(0,"clntNo") == ds_paymentCommissionBasisInfo.getCellData(0,"clntNo")){
    	ds_paymentCommissionBasisInfo.setCellData(0,"clntNm", ds_paymentCommissionBasisInfo.getCellData(0,"clntNm")+" ");
	}else{
		ds_paymentCommissionBasisInfo.modifyRowStatus(i, 'R');
	}

	for(var i=0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++){
		if(ds_orderEachPaymentCommissionInfo.getCellData(i,"chk")=="1" && ds_orderEachPaymentCommissionInfo.getCellData(i,"extYn")=="N"){  // 오더별 하역지급수수료 테이블에 자료가 없으면 
			ds_orderEachPaymentCommissionInfo.modifyRowStatus(i, 'R');
		}
	}

	for(var i=0; i<= ds_orderEachPaymentCommissionInfo.getRowCount() ; i++){
		if(ds_orderEachPaymentCommissionInfo.getCellData(i,"chk")=="1"){
	    	count++;
	    	break;
		}
    }

    //작업일자 셋팅
   if(! await scwin.f_setRsltsStdDt()) {
   	 return;
   }

	for(var i=0; i<ds_carryingVesselCompletionInformation.getRowCount(); i++) {
		ed_impExpClsNm.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsNm"));	
		ed_cvsslWrkCompleteYn.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn"));	
		ed_cvsslWrkCompleteDt.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));	
    }

    if(count<=0 && count1<=0){
    	await $c.gus.cfAlertMsg(MSG_CM_ERR_056,["오더번호"]);
	    return false;
    }else{

        let rtn = await $c.win.confirm("저장하시겠습니까");
	    if( rtn ){ 	
    		let objSubmit = await $c.sbm.execute(sbm_save);
            if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
                scwin.sbm_save_submitDone();
            } 
        }
    }

};

//-------------------------------------------------------------------------
// 작업완료일자 셋팅
//------------------------------------------------------------------------- 
//-------------------------------------------------------------------------
scwin.f_setRsltsStdDt = async function() {  

    //실적기준일자 셋팅 , 20060607 김상철 ppc
    // . 수출입 확인
    var checkImp = "";
    var checkDateSetting = "";

    for(var i=0; i<= ds_orderEachPaymentCommissionInfo.getRowCount() ; i++){
        if(ds_orderEachPaymentCommissionInfo.getRowStatus(i) != "D" ) { //삭제가 아닐경우

	        if((ds_orderEachPaymentCommissionInfo.getCellData(i, "chk" ) == "1") && (ds_orderEachPaymentCommissionInfo.getCellData(i,"odrNo") != "") ) {
		    var check = ds_orderEachPaymentCommissionInfo.getCellData(i,"rsltsStdDt"); 
			    if(check == "" ) {
			    	//alert(" 수출입 구분 첫번째  >> "+ds_orderEachPaymentCommissionInfo.NameValue(i,"impExpDomesticClsCd"));
			    	if(ds_orderEachPaymentCommissionInfo.getCellData(i,"impExpDomesticClsCd") == "수입" ){
			    	  	checkImp = "T";
			    	} else  {
						checkImp = "F";
			    	}  
			        if(checkImp == "T" ) { //수입일 경우 
						for(var j=0; j<= ds_carryingVesselCompletionInformation.getRowCount() ; j++){
							if(ds_orderEachPaymentCommissionInfo.getCellData(i, "chk" ) == "1" ) {
							    ed_impExpClsNm.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsNm"));	
							    ed_cvsslWrkCompleteYn.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn"));	
							    ed_cvsslWrkCompleteDt.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));	
		                        //alert(" 수출입 구분"+impExpClsNm);
		                        //alert(" 본선완료여부"+cvsslWrkCompleteYn);
		                        //alert(" 작업 완료 일자"+cvsslWrkCompleteDt);
		                        if ((ed_cvsslWrkCompleteYn.getValue() == "1") && (ds_orderEachPaymentCommissionInfo.getCellData(i,"impExpDomesticClsCd") == ed_impExpClsNm.getValue() )) {
						            ds_orderEachPaymentCommissionInfo.setCellData(i,"rsltsStdDt", ed_cvsslWrkCompleteDt.getValue());
							    } else {
							    	await $c.gus.cfAlertMsg(" 수입 구분이 다르거나 , 본선 완료가 되지 않았습니다.");
							    	return false;
							    }
						    }
					    }
				    } else if(checkImp == "F" ) { //수입이 아닐경우

						 for(var j=0; j<=ds_carryingVesselCompletionInformation.getRowCount() ; j++){
 							if(ds_orderEachPaymentCommissionInfo.getCellData(i, "chk" ) == "1" ) {
							    ed_impExpClsNm.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsNm"));	
							    ed_cvsslWrkCompleteYn.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn"));	
							    ed_cvsslWrkCompleteDt.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));	

							    if ((ed_cvsslWrkCompleteYn.getValue() == "1") && (ds_orderEachPaymentCommissionInfo.getCellData(i,"impExpDomesticClsCd") == "수출" )) {
						            ds_orderEachPaymentCommissionInfo.setCellData(i,"rsltsStdDt", ed_cvsslWrkCompleteDt.getValue());
							    } else {
							    	await $c.win.cfAlertMsg(" 수출 구분이 다르거나 , 본선 완료가 되지 않았습니다.");
							    	return false;
							    }
					        }
				        }
				    }

		        }
	    	}
	    } 	
    }
    return true;

};

//-------------------------------------------------------------------------
// 본선관리번호 검색
//------------------------------------------------------------------------- 
//-------------------------------------------------------------------------
scwin.f_openPopUp = function() {

    var	arrParam = new Array(1);
	var	rtnList = new Array();
	arrParam[0] = ed_cvsslMgntNo.getValue(); //라인번호
	arrParam[1] = ""; //배차점소

	//rtnList = window.showModalDialog("/tn/op/transwrkindict/cntr/tn_304_01_09p.jsp",arrParam,"dialogWidth:1000px; dialogHeight:400px; status:No");

    var data = {
          paramTitle       : "본선관리번호검색팝업"
        , arrParam         : arrParam
        , callbackFn       : scwin.f_openPopUp_callBackFunc
    };

    var opts = {
          id : "smpPop"
        , popupName : "본선관리번호검색팝업"
        , title : "본선관리번호검색화면"
        , modal : true
