	// 	psearch="07";
	// } else if (acb_payCmisKnd.getValue() == "6" || acb_payCmisKnd.getValue() == "7"|| acb_payCmisKnd.getValue() == "10") { // 6^화물입항료,7^화물입항료(기계화),10^화물입출항료(전도금용)이면 
	// 	psearch="15";
	// } else {
	// 	psearch="08";
	// } 
	switch (disGubun)
  	{
  	case 1:
		//매입거래처 
        ed_clnt.setSelectId("retrieveClntList");
		 await ed_clnt.cfCommonPopUp(scwin.retrieveClntNoInfoCb	// XML상의 SELECT ID	
								,pCode					// 화면에서의 ??? Code Element의	Value
								,pName					// 화면에서의 ??? Name Element의	Value
								,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
								,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
								,null					// Title순서	
								,null					// 보여주는 각 컬럼들의 폭	
								,null					// 컬럼중에서 숨기는	컬럼 지정	
								,psearch					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
								,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
