scwin.gr_orderEachPaymentCommissionInfo_oneditend = function (rowIndex, columnIndex, value) {
    var row = rowIndex;
    var col = columnIndex;
    if(col == 14){

        ed_rmkLength.setValue(ds_orderEachPaymentCommissionInfo.getCellData(row,"rmk")) ;
        var inputVal = ed_rmkLength.getValue();
        var maxLength =100;

        if($c.gus.cfGetByteLength(inputVal) > maxLength){
            while ($c.gus.cfGetByteLength(inputVal) > maxLength) {
                inputVal = inputVal.substring(0, inputVal.length-1);
            }
            ed_rmkLength.getValue(inputVal);
        };
        ds_orderEachPaymentCommissionInfo.setCellData(row,"rmk", ed_rmkLength.getValue());    

    }
};

